var minOperations = function(boxes) {
    const n = boxes.length;
    const ans = new Array(n).fill(0);
    let count = 0, cost = 0;
    for (let i = 0; i < n; i++) {
        ans[i] += cost;
        if (boxes[i] === '1') count++;
        cost += count;
    }
    count = 0; cost = 0;
    for (let i = n - 1; i >= 0; i--) {
        ans[i] += cost;
        if (boxes[i] === '1') count++;
        cost += count;
    }
    return ans;
};
